/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r * 0.299 + g * 0.587 + b * 0.114);
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Generates a high-resolution grayscale buffer for motion estimation.
 * Uses a 32x32 grid (1024 points).
 */
export function getStabilityBuffer(canvas: HTMLCanvasElement): Uint8Array {
  const size = 32;
  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = size;
  tempCanvas.height = size;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return new Uint8Array(size * size);

  tempCtx.drawImage(canvas, 0, 0, size, size);
  const imageData = tempCtx.getImageData(0, 0, size, size);
  const pixels = imageData.data;
  const buffer = new Uint8Array(size * size);

  for (let i = 0; i < size * size; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    buffer[i] = (r * 0.299 + g * 0.587 + b * 0.114);
  }
  return buffer;
}

/**
 * Calculates the difference between two stability buffers using SAD.
 * Returns a value from 0 (identical) to 100 (maximal difference).
 */
export function calculateDifference(b1: Uint8Array, b2: Uint8Array): number {
  if (b1.length !== b2.length) return 100;
  let totalDiff = 0;
  for (let i = 0; i < b1.length; i++) {
    totalDiff += Math.abs(b1[i] - b2[i]);
  }
  // Normalize by 255 (max brightness) and buffer length
  return (totalDiff / (b1.length * 255)) * 100;
}

/**
 * Calculates sharpness and detail metrics.
 * High variance usually implies a sharp, settled UI.
 */
export function calculateImageMetrics(canvas: HTMLCanvasElement): { blurScore: number; edgeIntensity: number } {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return { blurScore: 0, edgeIntensity: 0 };

  const width = canvas.width;
  const height = canvas.height;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  let edgeSum = 0;
  const sampleStep = 32; 
  const sampledGrays: number[] = [];

  for (let i = 0; i < data.length - sampleStep; i += sampleStep) {
    const gray = (data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114);
    sampledGrays.push(gray);
    mean += gray;

    // Local delta for edge detection
    const nextGray = (data[i + 4] * 0.299 + data[i + 5] * 0.587 + data[i + 6] * 0.114);
    edgeSum += Math.abs(gray - nextGray);
  }

  mean /= sampledGrays.length;

  let variance = 0;
  for (const v of sampledGrays) {
    variance += (v - mean) * (v - mean);
  }
  variance /= sampledGrays.length;

  return {
    blurScore: variance, 
    edgeIntensity: edgeSum / sampledGrays.length
  };
}

/**
 * Compares two hashes using Hamming Distance.
 */
export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { motion, AnimatePresence } from 'framer-motion';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateImageMetrics, hammingDistance, getStabilityBuffer, calculateDifference } from './services/videoProcessor';
import FrameGallery from './components/FrameGallery';

const FRAME_INTERVAL = 1.0; 
const REFINE_INTERVAL = 0.1;
const REFINE_DURATION = 5.0; 
const SIMILARITY_THRESHOLD = 8; 
const BLUR_THRESHOLD = 450; // Increased for stricter quality
const MOTION_STABILITY_THRESHOLD = 1.2; // Max % diff allowed in stability window
const TEMPORAL_WINDOW = [-0.2, -0.1, 0.1, 0.2]; // Relative offsets for stability check

interface FrameMetadata {
  hash: string;
  buffer: Uint8Array;
  metrics: { blurScore: number, edgeIntensity: number };
}

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [filteredFrames, setFilteredFrames] = useState<ExtractedFrame[]>([]);
  const [viewMode, setViewMode] = useState<'valid' | 'filtered'>('valid');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [quickViewFrame, setQuickViewFrame] = useState<ExtractedFrame | null>(null);
  const [progress, setProgress] = useState(0);
  const [isDownloading, setIsDownloading] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg'>('png');
  const [exportQuality, setExportQuality] = useState(0.9);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0,
    transitionCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setFrames([]);
      setFilteredFrames([]);
      setSelectedIds(new Set());
      setQuickViewFrame(null);
      setStats({
        totalFramesAnalyzed: 0,
        duplicateCount: 0,
        blurryCount: 0,
        stableCount: 0,
        transitionCount: 0
      });
      setStatus(ProcessingStatus.IDLE);
      setViewMode('valid');
    }
  };

  const getFrameMetadata = async (time: number): Promise<FrameMetadata> => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const fallback = { hash: '', buffer: new Uint8Array(0), metrics: { blurScore: 0, edgeIntensity: 0 } };

    if (!video || !canvas) return fallback;

    return new Promise((resolve) => {
      const onSeeked = async () => {
        video.removeEventListener('seeked', onSeeked);
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (!ctx) return resolve(fallback);

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const metrics = calculateImageMetrics(canvas);
        const hash = await calculateAverageHash(canvas);
        const buffer = getStabilityBuffer(canvas);
        resolve({ hash, buffer, metrics });
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration));
    });
  };

  const captureSingleFrameAt = async (time: number, currentExtracted: ExtractedFrame[], currentFiltered: ExtractedFrame[], localStats: ProcessingStats, hashes: string[], bypassFilters = false): Promise<void> => {
    if (!videoRef.current || !canvasRef.current) return;
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    // 1. Capture Target (Central) Frame
    const central = await getFrameMetadata(time);
    localStats.totalFramesAnalyzed++;

    if (bypassFilters) {
      const dataUrl = canvas.toDataURL('image/png');
      currentExtracted.push({
        id: `manual-${Math.random().toString(36).substr(2, 9)}`,
        timestamp: time,
        dataUrl,
        blurScore: central.metrics.blurScore,
        hash: central.hash,
        isStable: true,
        isUnique: true
      });
      setStats({ ...localStats });
      return;
    }

    // 2. Multi-point Temporal Stability Analysis
    let maxInstability = 0;
    for (const offset of TEMPORAL_WINDOW) {
      const sampleTime = time + offset;
      if (sampleTime < 0 || sampleTime > video.duration) continue;

      const sample = await getFrameMetadata(sampleTime);
      const diff = calculateDifference(central.buffer, sample.buffer);
      if (diff > maxInstability) maxInstability = diff;

      // Early exit if already too unstable
      if (maxInstability > MOTION_STABILITY_THRESHOLD) break;
    }

    const isSharp = central.metrics.blurScore > BLUR_THRESHOLD;
    const isStableUI = maxInstability <= MOTION_STABILITY_THRESHOLD; 

    let filterReason: ExtractedFrame['filterReason'] = undefined;

    if (!isSharp) {
      filterReason = 'blurry';
      localStats.blurryCount++;
    } else if (!isStableUI) {
      filterReason = 'transition';
      localStats.transitionCount++;
    } else {
      let isUnique = true;
      for (const h of hashes) {
        if (hammingDistance(central.hash, h) < SIMILARITY_THRESHOLD) {
          isUnique = false;
          filterReason = 'duplicate';
          localStats.duplicateCount++;
          break;
        }
      }

      if (isUnique) {
        localStats.stableCount++;
        hashes.push(central.hash);
        // We re-seek to central time just to be sure we draw the right frame to the final canvas for toDataURL
        // This is necessary because getFrameMetadata(lastOffset) left the video at a different time
        await new Promise<void>((res) => {
          const onFinalSeeked = () => {
            video.removeEventListener('seeked', onFinalSeeked);
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            res();
          };
          video.addEventListener('seeked', onFinalSeeked);
          video.currentTime = time;
        });

        const dataUrl = canvas.toDataURL('image/png');
        currentExtracted.push({
          id: Math.random().toString(36).substr(2, 9),
          timestamp: time,
          dataUrl,
          blurScore: central.metrics.blurScore,
          hash: central.hash,
          isStable: true,
          isUnique: true
        });
      }
    }

    if (filterReason && filterReason !== 'duplicate') {
      // For rejected frames, we also need to re-seek to capture the image correctly
      await new Promise<void>((res) => {
        const onFinalSeeked = () => {
          video.removeEventListener('seeked', onFinalSeeked);
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          res();
        };
        video.addEventListener('seeked', onFinalSeeked);
        video.currentTime = time;
      });

      const dataUrl = canvas.toDataURL('image/png');
      currentFiltered.push({
        id: `filtered-${Math.random().toString(36).substr(2, 9)}`,
        timestamp: time,
        dataUrl,
        blurScore: central.metrics.blurScore,
        hash: central.hash,
        isStable: false,
        isUnique: true,
        filterReason
      });
    }

    setStats({ ...localStats });
  };

  const captureManualSnapshot = async () => {
    if (!videoRef.current) return;
    const currentTime = videoRef.current.currentTime;
    const newExtracted = [...frames];
    const newFiltered = [...filteredFrames];
    const hashes = frames.map(f => f.hash);
    const localStats = { ...stats };

    await captureSingleFrameAt(currentTime, newExtracted, newFiltered, localStats, hashes, true);

    const sorted = newExtracted.sort((a, b) => a.timestamp - b.timestamp);
    setFrames(sorted);
    setFilteredFrames(newFiltered);
    setSelectedIds(prev => {
      const next = new Set(prev);
      const manuals = sorted.filter(f => f.id.startsWith('manual'));
      manuals.forEach(f => next.add(f.id));
      return next;
    });
    setViewMode('valid');
  };

  const deleteFrame = (id: string) => {
    setFrames(prev => prev.filter(f => f.id !== id));
    setFilteredFrames(prev => prev.filter(f => f.id !== id));
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.delete(id);
      return next;
    });
  };

  const restoreFrame = (id: string) => {
    const frameToRestore = filteredFrames.find(f => f.id === id);
    if (frameToRestore) {
      setFilteredFrames(prev => prev.filter(f => f.id !== id));
      const restored = { ...frameToRestore, filterReason: 'manual-restored' as const };
      const newFrames = [...frames, restored].sort((a, b) => a.timestamp - b.timestamp);
      setFrames(newFrames);
    }
  };

  const restoreSelectedFrames = () => {
    const toRestore = filteredFrames.filter(f => selectedIds.has(f.id));
    if (toRestore.length === 0) return;

    const restoreIds = new Set(toRestore.map(f => f.id));
    setFilteredFrames(prev => prev.filter(f => !restoreIds.has(f.id)));

    const restoredWithStatus = toRestore.map(f => ({
      ...f,
      filterReason: 'manual-restored' as const
    }));

    const newFrames = [...frames, ...restoredWithStatus].sort((a, b) => a.timestamp - b.timestamp);
    setFrames(newFrames);
    setViewMode('valid');
  };

  const processVideo = async () => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setFilteredFrames([]);
    setSelectedIds(new Set());
    setProgress(0);

    const duration = videoRef.current.duration;
    const extracted: ExtractedFrame[] = [];
    const filtered: ExtractedFrame[] = [];
    const hashes: string[] = [];
    let localStats = { totalFramesAnalyzed: 0, duplicateCount: 0, blurryCount: 0, stableCount: 0, transitionCount: 0 };

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await captureSingleFrameAt(time, extracted, filtered, localStats, hashes);
      setProgress(Math.min(100, (time / duration) * 100));
    }

    setFrames(extracted);
    setFilteredFrames(filtered);
    setSelectedIds(new Set(extracted.map(f => f.id)));
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
    setViewMode('valid');
  };

  const refineFromFrame = async (frame: ExtractedFrame) => {
    if (!videoRef.current) return;
    setStatus(ProcessingStatus.ANALYZING);
    setProgress(0);

    const startTime = frame.timestamp;
    const endTime = Math.min(startTime + REFINE_DURATION, videoRef.current.duration);
    const newExtracted: ExtractedFrame[] = [...frames];
    const newFiltered: ExtractedFrame[] = [...filteredFrames];
    const hashes: string[] = frames.map(f => f.hash);

    let localStats = { ...stats };

    for (let time = startTime; time < endTime; time += REFINE_INTERVAL) {
      await captureSingleFrameAt(time, newExtracted, newFiltered, localStats, hashes);
      setProgress(Math.min(100, ((time - startTime) / (endTime - startTime)) * 100));
    }

    const sortedFrames = newExtracted.sort((a, b) => a.timestamp - b.timestamp);
    setFrames(sortedFrames);
    setFilteredFrames(newFiltered);
    setSelectedIds(new Set(sortedFrames.map(f => f.id)));
    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
    setViewMode('valid');
  };

  const toggleFrameSelection = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const toggleAllSelection = (selected: boolean) => {
    const currentList = viewMode === 'valid' ? frames : filteredFrames;
    if (selected) {
      setSelectedIds(new Set([...selectedIds, ...currentList.map(f => f.id)]));
    } else {
      const next = new Set(selectedIds);
      currentList.forEach(f => next.delete(f.id));
      setSelectedIds(next);
    }
  };

  const convertImage = (dataUrl: string, format: 'png' | 'jpeg', quality: number): Promise<string> => {
    return new Promise((resolve) => {
      if (format === 'png') {
        resolve(dataUrl);
        return;
      }
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = img.width;
        canvas.height = img.height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0);
          resolve(canvas.toDataURL('image/jpeg', quality));
        } else {
          resolve(dataUrl);
        }
      };
      img.src = dataUrl;
    });
  };

  const downloadFrame = async (frame: ExtractedFrame) => {
    const formattedUrl = await convertImage(frame.dataUrl, exportFormat, exportQuality);
    const link = document.createElement('a');
    link.download = `frame-${frame.timestamp.toFixed(2)}s.${exportFormat}`;
    link.href = formattedUrl;
    link.click();
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0 || !videoFile) return;
    setIsDownloading(true);
    try {
      const zip = new JSZip();
      const allPossibleFrames = [...frames, ...filteredFrames];
      const sortedSelectedFrames = allPossibleFrames
        .filter(f => selectedIds.has(f.id))
        .sort((a, b) => a.timestamp - b.timestamp);

      for (let i = 0; i < sortedSelectedFrames.length; i++) {
        const frame = sortedSelectedFrames[i];
        const formattedUrl = await convertImage(frame.dataUrl, exportFormat, exportQuality);
        const base64Data = formattedUrl.split(',')[1];
        zip.file(`${i + 1}.${exportFormat}`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      const videoBaseName = videoFile.name.replace(/\.[^/.]+$/, "");
      link.download = `${videoBaseName}.zip`;
      link.click();
    } catch (error) {
      console.error("Download Error:", error);
    } finally {
      setIsDownloading(false);
    }
  };

  const activeFrames = viewMode === 'valid' ? frames : filteredFrames;
  const selectedFilteredCount = filteredFrames.filter(f => selectedIds.has(f.id)).length;

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-8 sm:px-6 lg:px-8 min-h-screen flex flex-col">
      <header className="mb-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6 flex-shrink-0">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">
            Anatomi <span className="text-blue-500">Video Editor</span>
          </h1>
          <p className="text-gray-400 text-xs mt-1">
            Intelligent frame extraction for high-quality visual auditing.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-5 py-2.5 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2 text-sm">
            <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
            <span className="font-semibold">Upload</span>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
          </label>

          <button 
            disabled={!videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)}
            onClick={processVideo}
            className={`px-6 py-2.5 rounded-xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg text-sm ${
              !videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed opacity-50'
                : 'bg-blue-600 hover:bg-blue-500 text-white active:scale-95'
            }`}
          >
            {status === ProcessingStatus.IDLE || status === ProcessingStatus.COMPLETED ? (
              <>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                </svg>
                <span>Extract Frames</span>
              </>
            ) : (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                <span>Analyzing...</span>
              </>
            )}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0 mb-20">
        <div className="lg:col-span-3 flex flex-col gap-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-4 shadow-xl flex flex-col">
            <h2 className="text-xs font-black mb-3 flex items-center gap-2 uppercase tracking-widest text-gray-500">
              <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              Input Source
            </h2>

            <div className="bg-black rounded-xl overflow-hidden border border-gray-800 relative shadow-2xl transition-all duration-500">
              {videoUrl ? (
                <video ref={videoRef} src={videoUrl} className="w-full h-auto block object-contain" controls />
              ) : (
                <div className="w-full aspect-video flex items-center justify-center text-gray-600 text-[10px] italic p-6 text-center">
                  Awaiting video upload...
                </div>
              )}

              {status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED && (
                 <div className="absolute inset-x-0 bottom-0 p-3 bg-gradient-to-t from-black to-transparent">
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-[8px] font-black text-blue-400 uppercase tracking-widest animate-pulse">Advanced Scanning</span>
                      <span className="text-[8px] font-black text-white">{Math.round(progress)}%</span>
                    </div>
                    <div className="w-full bg-gray-800 rounded-full h-1 overflow-hidden">
                      <motion.div 
                        initial={{ width: 0 }}
                        animate={{ width: `${progress}%` }}
                        className="bg-blue-500 h-full"
                      />
                    </div>
                 </div>
              )}
            </div>

            <canvas ref={canvasRef} className="hidden" />

            <div className="mt-4 space-y-3">
              <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => setViewMode('valid')}
                  className={`flex flex-col items-start p-3 rounded-xl border transition-all text-left group ${viewMode === 'valid' ? 'bg-blue-600/10 border-blue-600' : 'bg-gray-800/50 border-gray-700/50'}`}
                >
                  <div className={`text-lg font-bold ${viewMode === 'valid' ? 'text-blue-400' : 'text-gray-300'}`}>{stats.stableCount}</div>
                  <div className="text-[8px] text-gray-500 uppercase font-black">Valid</div>
                </button>
                <button 
                  onClick={() => setViewMode('filtered')}
                  className={`flex flex-col items-start p-3 rounded-xl border transition-all text-left group ${viewMode === 'filtered' ? 'bg-orange-600/10 border-orange-600' : 'bg-gray-800/50 border-gray-700/50'}`}
                >
                  <div className={`text-lg font-bold ${viewMode === 'filtered' ? 'text-orange-400' : 'text-gray-300'}`}>{filteredFrames.length}</div>
                  <div className="text-[8px] text-gray-500 uppercase font-black">Filtered</div>
                </button>
              </div>
              <div className="p-3 bg-gray-800/30 rounded-xl border border-gray-700/50 text-[9px] space-y-1">
                 <div className="flex justify-between font-bold text-gray-500 uppercase tracking-widest">
                    <span>Duplicates</span>
                    <span className="text-gray-300">{stats.duplicateCount}</span>
                 </div>
                 <div className="flex justify-between font-bold text-gray-500 uppercase tracking-widest">
                    <span>Transitions</span>
                    <span className="text-gray-300">{stats.transitionCount}</span>
                 </div>
                 <div className="flex justify-between font-bold text-gray-500 uppercase tracking-widest">
                    <span>Blurry</span>
                    <span className="text-gray-300">{stats.blurryCount}</span>
                 </div>
              </div>
            </div>
          </section>
        </div>

        <div className="lg:col-span-9 flex flex-col gap-4 min-h-0">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-gray-900/30 p-4 rounded-2xl border border-gray-800/50 flex-shrink-0">
            <div className="flex flex-col gap-2">
              <div className="flex items-center gap-3">
                <h2 className="text-xl font-bold text-white">
                  {viewMode === 'valid' ? 'Audit Gallery' : 'Filtered Content'}
                </h2>
                <div className="flex p-1 bg-gray-950 rounded-lg border border-gray-800">
                  <button onClick={() => setViewMode('valid')} className={`px-4 py-1 rounded text-[10px] font-bold transition-all ${viewMode === 'valid' ? 'bg-gray-800 text-blue-400' : 'text-gray-500'}`}>Valid</button>
                  <button onClick={() => setViewMode('filtered')} className={`px-4 py-1 rounded text-[10px] font-bold transition-all ${viewMode === 'filtered' ? 'bg-gray-800 text-orange-400' : 'text-gray-500'}`}>Filtered</button>
                </div>
              </div>
              <span className="text-[10px] text-gray-400 font-medium uppercase tracking-widest">
                {selectedIds.size} of {activeFrames.length} selected
              </span>
            </div>

            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 bg-gray-800/50 px-3 py-1.5 rounded-lg border border-gray-700">
                <div className="flex flex-col">
                  <span className="text-[7px] font-black text-gray-500 uppercase tracking-widest">Format</span>
                  <select value={exportFormat} onChange={(e) => setExportFormat(e.target.value as 'png' | 'jpeg')} className="bg-transparent text-[10px] font-bold text-white outline-none cursor-pointer p-0 border-none focus:ring-0">
                    <option value="png" className="bg-gray-900">PNG</option>
                    <option value="jpeg" className="bg-gray-900">JPEG</option>
                  </select>
                </div>
                {exportFormat === 'jpeg' && (
                  <>
                    <div className="h-6 w-px bg-gray-700 mx-1" />
                    <div className="flex flex-col min-w-[60px]">
                      <span className="text-[7px] font-black text-gray-500 uppercase tracking-widest">Quality {Math.round(exportQuality * 100)}%</span>
                      <input type="range" min="0.1" max="1" step="0.05" value={exportQuality} onChange={(e) => setExportQuality(parseFloat(e.target.value))} className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
                    </div>
                  </>
                )}
              </div>

              <div className="flex items-center gap-2">
                {viewMode === 'filtered' && selectedFilteredCount > 0 && (
                  <button onClick={restoreSelectedFrames} className="px-4 py-2 rounded-xl font-bold bg-blue-600 hover:bg-blue-500 text-white text-[10px] uppercase tracking-widest">Restore</button>
                )}
                {(frames.length > 0 || filteredFrames.length > 0) && (
                  <button 
                    disabled={selectedIds.size === 0 || isDownloading} 
                    onClick={downloadSelected} 
                    className={`px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2 text-[10px] uppercase tracking-widest ${selectedIds.size === 0 || isDownloading ? 'bg-gray-800 text-gray-600 cursor-not-allowed border border-gray-700' : 'bg-green-600 hover:bg-green-500 text-white active:scale-95'}`}
                  >
                    {isDownloading ? 'Zipping...' : `Export (${selectedIds.size})`}
                  </button>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 min-h-0">
             <FrameGallery 
              frames={activeFrames} 
              selectedIds={selectedIds}
              onToggleSelection={toggleFrameSelection}
              onToggleAll={toggleAllSelection}
              onDownload={downloadFrame} 
              onRefine={refineFromFrame}
              onDelete={deleteFrame}
              onView={(frame) => setQuickViewFrame(frame)}
              onRestore={viewMode === 'filtered' ? restoreFrame : undefined}
            />
          </div>
        </div>
      </main>

      <AnimatePresence>
        {quickViewFrame && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex flex-col p-6">
            <div className="flex justify-between items-center mb-6 max-w-6xl mx-auto w-full">
              <div className="flex items-center gap-4">
                <h3 className="text-xl font-bold text-white uppercase tracking-tighter">Frame Inspection</h3>
                <span className="text-blue-400 font-mono text-sm bg-blue-400/10 px-3 py-1 rounded-lg border border-blue-400/20">{quickViewFrame.timestamp.toFixed(2)}s</span>
              </div>
              <button onClick={() => setQuickViewFrame(null)} className="p-2 bg-gray-800 hover:bg-red-600 rounded-full transition-all text-white"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="flex-1 overflow-hidden rounded-2xl border border-gray-800 bg-gray-950 flex items-center justify-center p-2 max-w-6xl mx-auto w-full">
              <motion.img initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} src={quickViewFrame.dataUrl} className="max-w-full max-h-full object-contain" />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {videoUrl && (
        <div className="fixed bottom-24 right-8 z-[80]">
          <motion.button 
            initial={{ scale: 0 }} animate={{ scale: 1 }} whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
            onClick={captureManualSnapshot}
            className="w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full shadow-2xl flex items-center justify-center text-white border-4 border-blue-400/20"
            title="Manual Capture"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </motion.button>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-gray-950/90 backdrop-blur-xl border-t border-gray-800 p-3 z-[90]">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 text-[9px] font-black uppercase tracking-[0.2em] text-gray-500">
            <div className="flex items-center gap-1.5">
              <span className={`w-1.5 h-1.5 rounded-full ${status === ProcessingStatus.COMPLETED ? 'bg-green-500' : status === ProcessingStatus.IDLE ? 'bg-gray-600' : 'bg-blue-500 animate-pulse'}`} />
              <span>{status}</span>
            </div>
            {videoFile && <><span className="text-gray-800">|</span><span className="text-gray-400 lowercase font-medium tracking-normal">{videoFile.name}</span></>}
          </div>
          <div className="text-[9px] text-gray-700 uppercase font-black tracking-[0.3em] hidden sm:block">Anatomi Precision Engine</div>
        </div>
      </footer>
    </div>
  );
};

export default App;
